import React, { useMemo, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { Button, Select, DateRangeFilter, Pagination, addToast } from '@linm-soft/common-components';
import type { DateRangeValue } from '@linm-soft/common-components';
import { useAppDispatch } from '../../store/hooks';
import { useVoucherListFilterState } from '../../hooks/useVoucherListFilterState';
import { useVoucherInitData } from '../../hooks/useVoucherInitData';
import { ktService } from '../../services/kt/ktService';
import type { JournalEntryDto } from '../../services/kt/models';
import { JOURNAL_ENTRY_NKC_CONFIG, type JournalEntryPageConfig } from '../../constants/journalEntryPageConfig';
import { formatDateLocal } from '../../utils/formatters';
import { getApiErrorMessage } from '../../utils/getApiErrorMessage';
import { formatProcessingLevelFromOptions } from '../../utils/voucherProcessingLevelOptions';
import erp from '../../styles/erpPage.module.css';
import { ListSearchRefreshButtons } from '../list/ListSearchRefreshButtons';
import { ProcessingLevelApproveModal } from '../voucher/ProcessingLevelApproveModal';

const PAGE_SIZE = 20;

function isRowSelectable(row: JournalEntryDto): boolean {
  return row.status === 'Draft';
}

export interface JournalEntryListProps {
  config?: JournalEntryPageConfig;
}

export const JournalEntryList: React.FC<JournalEntryListProps> = ({ config = JOURNAL_ENTRY_NKC_CONFIG }) => {
  const dispatch = useAppDispatch();
  const navigate = useNavigate();

  const { processingLevelOptions, defaultProcessingLevel } = useVoucherInitData(config.initDataListFormName);

  const processingFilterOptions = useMemo(
    () => [{ value: '', label: 'Tất cả mức xử lý' }, ...processingLevelOptions],
    [processingLevelOptions],
  );

  const formatProcessingLabel = (level: string | undefined) =>
    formatProcessingLevelFromOptions(level, processingLevelOptions);

  const {
    initialized,
    fromDate,
    setFromDate,
    toDate,
    setToDate,
    processingLevel,
    setProcessingLevel,
    page,
    setPage,
    resetPage,
  } = useVoucherListFilterState(config.listFilterScope);

  const [items, setItems] = useState<JournalEntryDto[]>([]);
  const [totalCount, setTotalCount] = useState(0);
  const [loading, setLoading] = useState(false);
  const [reloadKey, setReloadKey] = useState(0);
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [showApproveModal, setShowApproveModal] = useState(false);
  const [approving, setApproving] = useState(false);

  const testId = config.testIdPrefix;

  const selectableOnPage = useMemo(
    () => items.filter(isRowSelectable),
    [items],
  );
  const allSelectableSelected = selectableOnPage.length > 0
    && selectableOnPage.every(r => selectedIds.includes(r.id));

  const handleSearch = () => {
    resetPage();
    setSelectedIds([]);
    setReloadKey(k => k + 1);
  };
  const refresh = () => {
    setSelectedIds([]);
    setReloadKey(k => k + 1);
  };

  React.useEffect(() => {
    if (!initialized) return;
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      ktService.getJournalEntries({
        fromDate,
        toDate,
        processingLevel: processingLevel || undefined,
        entryKind: config.entryKind,
        page,
        pageSize: PAGE_SIZE,
      })
        .then(res => { if (!cancelled) { setItems(res.items); setTotalCount(res.totalCount); } })
        .catch(err => {
          if (!cancelled) {
            dispatch(addToast({ message: getApiErrorMessage(err, 'Lỗi tải danh sách'), type: 'error' }));
          }
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [fromDate, toDate, processingLevel, page, reloadKey, dispatch, config.entryKind, initialized]);

  const toggleRow = (id: string, checked: boolean) => {
    setSelectedIds(prev => (checked ? [...prev, id] : prev.filter(x => x !== id)));
  };

  const toggleSelectAll = () => {
    if (allSelectableSelected) {
      const pageIds = new Set(selectableOnPage.map(r => r.id));
      setSelectedIds(prev => prev.filter(id => !pageIds.has(id)));
    } else {
      const merged = new Set([...selectedIds, ...selectableOnPage.map(r => r.id)]);
      setSelectedIds([...merged]);
    }
  };

  const handleBatchApproveConfirm = async (newLevel: string) => {
    setApproving(true);
    try {
      await ktService.batchUpdateJournalEntryProcessingLevel({
        ids: selectedIds,
        processingLevel: newLevel,
      });
      dispatch(addToast({ message: 'Phê duyệt thành công', type: 'success' }));
      setShowApproveModal(false);
      setSelectedIds([]);
      setReloadKey(k => k + 1);
    } catch (err: unknown) {
      dispatch(addToast({
        message: getApiErrorMessage(err, 'Phê duyệt thất bại. Vui lòng thử lại.'),
        type: 'error',
      }));
    } finally {
      setApproving(false);
    }
  };

  return (
    <div className={erp.page} data-testid={`${testId}-list`}>
      <div className={erp.pageHeader}>
        <div className={erp.titleBlock}>
          <h1 className={erp.title} data-testid={`${testId}-title`}>
            <i className={`fas ${config.listIcon}`} /> {config.listTitle}
          </h1>
        </div>
        <div className={erp.headerActions}>
          <Button
            variant="secondary"
            data-testid={`${testId}-batch-approve-btn`}
            disabled={selectedIds.length === 0}
            onClick={() => setShowApproveModal(true)}
          >
            <i className="fas fa-check-double" /> Phê duyệt
          </Button>
          <Button
            variant="primary"
            data-testid={`${testId}-create-btn`}
            onClick={() => navigate(config.createPath)}
          >
            <i className="fas fa-plus" /> Tạo mới
          </Button>
        </div>
      </div>

      {selectedIds.length > 0 && (
        <div className={erp.batchBar} data-testid={`${testId}-batch-bar`}>
          <span>Đã chọn {selectedIds.length}</span>
          <button
            type="button"
            className={erp.batchBarLink}
            data-testid={`${testId}-batch-clear`}
            onClick={() => setSelectedIds([])}
          >
            Bỏ chọn tất cả
          </button>
        </div>
      )}

      <div className={erp.filtersBar} data-testid={`${testId}-filters`}>
        <DateRangeFilter
          fromDate={fromDate}
          toDate={toDate}
          onChange={(v: DateRangeValue) => { setFromDate(v.fromDate); setToDate(v.toDate); resetPage(); }}
        />
        <Select
          value={processingLevel}
          onChange={e => { setProcessingLevel(e.target.value); resetPage(); }}
          options={processingFilterOptions}
          data-testid={`${testId}-filter-processing-level`}
        />
        <ListSearchRefreshButtons testIdPrefix={testId} onSearch={handleSearch} onRefresh={refresh} />
      </div>

      <div className={erp.tableCard} data-testid={`${testId}-table`}>
        {loading ? <div className={erp.loading}>Đang tải...</div> : items.length === 0 ? <div className={erp.empty}>Không có dữ liệu</div> : (
          <div className={erp.tableWrapper}>
            <table className={erp.table}>
              <thead>
                <tr>
                  <th className={erp.colCheck}>
                    <input
                      type="checkbox"
                      data-testid={`${testId}-select-all`}
                      checked={allSelectableSelected}
                      disabled={selectableOnPage.length === 0}
                      onChange={toggleSelectAll}
                      aria-label="Chọn tất cả"
                    />
                  </th>
                  <th>Số CT</th>
                  <th>Ngày</th>
                  <th>Diễn giải</th>
                  <th>Mức xử lý</th>
                </tr>
              </thead>
              <tbody>
                {items.map(r => {
                  const selectable = isRowSelectable(r);
                  return (
                    <tr key={r.id}>
                      <td className={erp.colCheck}>
                        <input
                          type="checkbox"
                          data-testid={`${testId}-row-${r.id}-select`}
                          checked={selectedIds.includes(r.id)}
                          disabled={!selectable}
                          onChange={e => toggleRow(r.id, e.target.checked)}
                          aria-label={`Chọn ${r.code}`}
                        />
                      </td>
                      <td>
                        <button
                          type="button"
                          className={erp.codeLink}
                          data-testid={`${testId}-row-${r.id}-code`}
                          onClick={() => navigate(config.detailPath(r.id))}
                        >
                          <code>{r.code}</code>
                        </button>
                      </td>
                      <td>{formatDateLocal(r.entryDate)}</td>
                      <td>{r.description}</td>
                      <td data-testid={`${testId}-row-${r.id}-processing-level`}>
                        {formatProcessingLabel(r.processingLevel)}
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        )}
        {totalCount > 0 && (
          <div className={erp.paginationRow}>
            <Pagination
              currentPage={page}
              totalPages={Math.ceil(totalCount / PAGE_SIZE)}
              totalCount={totalCount}
              pageSize={PAGE_SIZE}
              onPageChange={p => { setPage(p); setSelectedIds([]); }}
            />
          </div>
        )}
      </div>

      <ProcessingLevelApproveModal
        isOpen={showApproveModal}
        onClose={() => setShowApproveModal(false)}
        currentLevel={defaultProcessingLevel ?? ''}
        levelOptions={processingLevelOptions}
        onConfirm={handleBatchApproveConfirm}
        saving={approving}
        testIdPrefix={testId}
      />
    </div>
  );
};
